import {BeSkill} from '@be/be-framework';

type YesNoMim = true | false | 'incomplete_interaction';

export default class Analytics {
    private skill:BeSkill;
    public person_id_successful:YesNoMim = 'incomplete_interaction';
    public person_in_loop:YesNoMim = 'incomplete_interaction';
    public enrollment_offered = false;

    constructor(skill:BeSkill) {
        this.skill = skill;
    }

    public opened(initial_hypothesis:boolean, confidence_rating:string) {
        // reset variables;
        this.person_id_successful = 'incomplete_interaction';
        this.person_in_loop = 'incomplete_interaction';
        this.enrollment_offered = false;

        this.skill.track('Who Am I Opened', { initial_hypothesis, confidence_rating });
    }

    public response() {
        this.skill.track('Who Am I Response', {
            person_id_successful: this.person_id_successful,
            person_in_loop: this.person_in_loop,
            enrollment_offered: this.enrollment_offered
        });
    }
}
