import { SpeakerIdInfo } from 'jibo-common-types';
import jibo = require('jibo');
import ContactsView = jibo.rendering.gui.views.ContactsView;
import ContactButton = jibo.rendering.gui.components.ContactButton;
import Label = jibo.rendering.gui.components.Label;

export default class FlowClass {

    public selectedLooper:string;
    public loopMember:jibo.kb.UserNode;
    public loopOwner:jibo.kb.UserNode;
    public menuTimeout:any;
    private guessedIDState:string;
    private log:any;
    private convTechLog:typeof jibo.log;

    constructor(log:any) {
        this.log = log;
        this.convTechLog = this.log.createChild('ConvTechSpeakerID');
        this.guessedIDState = null;
        this.sortLoopListOverride = this.sortLoopListOverride.bind(this);
    }

    public setGuessedIDState(state:string):void {
        this.guessedIDState = state;
    }

    public async setLoopMember(looper:string):Promise<void> {
        this.loopMember = await jibo.kb.loop.getUserNodeById(looper);
        this.log.debug(`set loopMember: ${looper}`);
    }

    public async setLoopOwner():Promise<void> {
        try {
            let node:jibo.kb.Node = await jibo.kb.loop.loadRoot();
            let ownerID:string = node.getEdges('owner')[0];
            this.loopOwner = await jibo.kb.loop.getUserNodeById(ownerID);
            this.log.debug(`got owner: ${ownerID}`);
        } catch (err) {
            this.log.error('Error querying the KB:', err);
        }
    }

    public async showLooperCoin():Promise<void> {
        return new Promise<void>((resolve, reject) => {
            this.log.info(`showLooperCoin`);
            let view:ContactsView = <ContactsView>jibo.face.views.createView('HypothesisView');

            view.sortLoopList = (loop) => {
                let currentLooper:jibo.kb.UserNode[] = [];
                for (let looper of loop) {
                    if (looper.id === this.loopMember.id) {
                        currentLooper.push(looper);
                        this.log.debug(`looper: ${looper.id}`);
                    }
                }
                return currentLooper;
            };

            const addViewOptions:jibo.rendering.gui.ChangeOptions = {
                addView: view,
                remove: true,
                transitionOpen: jibo.face.views.IN,
                transitionClose: jibo.face.views.OUT
            };
            const onViewComplete:jibo.face.views.ViewCallback = (view) => {
                (<ContactsView>view).list.getComponentByIndex(0).lockInput(true);
                resolve();
            };
            const onViewLoaded:jibo.face.views.ViewCallback = (view) => {
                view.id = 'looperCoin';

                const COIN_SIZE:number = 500;
                const CONTACT_BUTTON_SIZE:number = 330;
                const BUTTON_OFFSET:number = (COIN_SIZE - CONTACT_BUTTON_SIZE) / 2;

                let button:ContactButton = <ContactButton>(<ContactsView>view).list.getComponentByIndex(0);
                button.display.width = button.display.height = COIN_SIZE;
                button.display.x -= BUTTON_OFFSET;
                button.display.y -= BUTTON_OFFSET;

                let label:Label = <Label>view.getComponentById('buttonLabel0');
                label.display.y += 93;
                label.text += '?';
            };
            const onViewFailure:Function = (err) => {
                reject(err);
            };

            view.addAction('mimEnd', null, false, false, jibo.face.views.SWIPE);

            jibo.face.views.changeView(addViewOptions, onViewComplete, onViewFailure, onViewLoaded);
        });
    }

    public sortLoopListOverride(loop):jibo.kb.UserNode[] {
        this.log.info(`sortLoopListOverride`);
        let notEnrolled: jibo.kb.UserNode[] = [];
        let alreadyEnrolled: jibo.kb.UserNode[] = [];
        for (let looper of loop) {
            this.log.debug(`looper: ${looper.id}`);
            if (looper.isJibo) {
                continue;//INHUMAN!
            }
            if (looper.data.enrolled && looper.data.enrolled.voice && looper.data.enrolled.face) {
                alreadyEnrolled.push(looper);
            }
            else {
                notEnrolled.push(looper);
            }
        }
        return alreadyEnrolled.concat(notEnrolled);
    }

    public async removeView():Promise<void> {
        return new Promise<void>((resolve, reject) => {
            this.log.info(`removeView`);
            if (this.menuTimeout) {
                clearTimeout(this.menuTimeout);
                this.menuTimeout = null;
            }
            let view = jibo.face.views;
            let removeViewOptions:jibo.rendering.gui.ChangeOptions = {
                removeAll: true,
            };
            let onComplete = () => {
                resolve();
            };
            if (!view.currentView) {
                jibo.face.views.forceEyeView(onComplete, null, jibo.face.views.IN, jibo.face.views.DOWN, () => {
                    this.log.error(' failure during forceEyeView, calling complete anyway');
                    onComplete();
                });
            } else {
                if (view.currentView.id === 'eyeView') {
                    resolve();
                } else {
                    if (view.currentView.id === 'looperCoin') {
                        removeViewOptions.transitionClose = view.OUT;
                    }
                    jibo.face.views.changeView(removeViewOptions, onComplete, (err) => {
                        this.log.error("removing face view failed");
                        reject(err);
                    });
                }
            }
        });
    }

    public logResults(state:string, speakerInfo?:SpeakerIdInfo):void {
        // logs for ConvTech

        if (speakerInfo) {
            this.convTechLog.info(`${state} | Speaker ID: ${speakerInfo.id} | accepted: ${speakerInfo.accepted} | is high confidence: ${speakerInfo.highConfidence} | score: ${speakerInfo.score}`);
        } else {
            // Interaction error doesn't have speakerInfo
            this.convTechLog.info(state);
        }
    }
}
