/// <reference path="../typings/index.d.ts" />
import { BeSkill, Options, libraries } from '@be/be-framework';
import jibo = require('jibo');
import FlowClass from './FlowClass';
import HypothesisView from "./gui/HypothesisView";
import Analytics from './analytics/Analytics';
const { PromiseUtils } = libraries.jibo_cai_utils;

let mainFlow:any = require('./flows/hypothesis');

class WhoAmI extends BeSkill {

    public flow:any;
    private blackboard:any;
    private flowOverrides:any = null;
    private analytics: Analytics;
    /**
     * WhoAmI skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?:Options) {
        super(assetPack);
        this.flow = null;
        this.analytics = new Analytics(this);
    }

    preload(done:(err?:any)=>void):void {
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?:any, refresh?:boolean):void {
        if (refresh) {
            return this.close(() => {
                this.open(result);
            });
        }
        this.log.info('opening skill');
        jibo.face.views.creator.registerClass(HypothesisView);
        // Always force the eye view no matter what on open.
        jibo.face.views.forceEyeView();
        if(!result){
            this.log.debug('no result');
            this.exit();
            return;
        }

        this._open(result)
            .catch((err) => {
                this.log.error(err);
                this.exit();
            });
    }

    async _open(result:any):Promise<any> {
        this.blackboard = {
            log: this.log,
            flow: new FlowClass(this.log),
            analytics: this.analytics,
            looperGuess: "",
            speakerInfo: null,
            enrollmentType: null
        };
        const options = Object.assign({
            assetPack: this.assetPack,
            blackboard: this.blackboard,
            params: {
                context: result,
            },
            enableLogging: true
        }, this.flowOverrides);

        // for analytics
        let confidence_rating:string = '0';
        let hypothesis:boolean = false;

        const speaker = jibo.lps.identity.getActiveSpeaker();

        if (speaker) {
            hypothesis = true;
            const speakerInfo = speaker.idInfo;
            confidence_rating = speakerInfo.highConfidence ? 'HIGH_CONFIDENCE' : 'LOW_CONFIDENCE';
            this.blackboard.speakerInfo = speakerInfo;
            this.blackboard.looperGuess = speakerInfo.id;
        }
        this.blackboard.analytics.opened(hypothesis, confidence_rating);
        this.blackboard.flow.logResults(`Hypothesis: ${hypothesis}`, this.blackboard.speakerInfo);

        const status = await PromiseUtils.promisify(cb => {
            this.flow = jibo.flow.run(mainFlow, options, cb);
        });
        if (status === jibo.bt.Status.INTERRUPTED || !this.flow) {
            return;
        }
        if (this.flow.result && this.flow.result.transition === 'enrollment') {
            let redirectParams = {
                nlu: {
                    intent: 'enrollment',
                    entities: {
                        enrollmentType: this.blackboard.enrollmentType,
                        recipient: this.blackboard.flow.loopMember.id
                    }
                }
            };
            this.log.info(`redirect to enrollment. enrollmentType: ${this.blackboard.enrollmentType}. recipient: ${this.blackboard.flow.loopMember.id}`);
            this.redirect('@be/introductions', redirectParams);
        } else {
            this.exit();
        }
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done:() => void):void {
        this.log.debug('closing skill');
        jibo.face.views.creator.unregisterClass('HypothesisView');
        this.blackboard.analytics.response();
        if (this.flow) {
            Promise.all([
                this.flow.stopAndDestroy()
                .then(() => {
                    this.flow = null;
                }),

                new Promise((resolve) => {
                    if(jibo.face.views.currentView && jibo.face.views.currentView.id !== 'eyeView') {
                        jibo.face.views.changeView({removeAll: true, leaveEmpty: true}, () => {
                            resolve();
                        },
                        () => {
                            this.log.error("removing face view failed");
                            resolve();
                        });
                    } else {
                        jibo.face.views.forceEyeView(() => {
                            resolve();
                        },
                        null, // onLoaded callback
                        null, // use default transitionOpen
                        null, // use default transitionClose
                        () => {
                            this.log.error('view failure, continuing anyway');
                            resolve();
                        });
                    }
                })
            ]).then(() => {
                done();
            });
        }
        else {
            done();
        }
    }
}

module.exports = WhoAmI;
