import jibo = require('jibo');
import ActionData = jibo.face.views.ActionData;

export default class HypothesisView extends jibo.rendering.gui.views.ContactsView {
    public static get DEFAULT_TYPE():string {return 'HypothesisView';}

    protected _type:string = HypothesisView.DEFAULT_TYPE;
    
    public actionEnactor(action:ActionData):boolean {
        if (this._inputLocked) {
            return false;
        }
        //reject any verbal commands that are not closing the menu, because we do not want to
        //handle menu navigation commands for our 'list' of one giant item.
        //This specifically works around an NLU issue where "right" is parsed as the GUI command
        //even though the local version should win on heuristic score
        if (action.type === ActionData.VERBAL_COMMAND) {
            if (action.data.intent !== 'close') {
                console.warn('REJECTING NON CLOSE VERBAL COMMAND');
                return false;
            }
        }
        return super.actionEnactor(action);
    }
}
